const milestones = $input.first().json;

const users = Array.isArray(milestones) ? milestones : (milestones.users || milestones.milestones || []);

if (users.length === 0) {
  return [{ json: { skip: true, message: 'No milestones reached today' } }];
}

return users.map(user => ({
  json: {
    skip: false,
    userId: user.telegram_id || user.chat_id || user.id,
    username: user.username || user.first_name || 'there',
    milestone: user.milestone || user.milestone_type || '10_trades',
    milestoneCount: user.milestone_count || user.count || 10,
    totalPredictions: user.total_predictions || user.prediction_count || 0,
    accuracy: user.user_accuracy || user.personal_accuracy || null,
    winRate: user.win_rate || null,
    profitLoss: user.profit_loss || user.pnl || null,
    memberSince: user.member_since || user.created_at || null
  }
}));

const { username, milestone, milestoneCount, totalPredictions, accuracy, winRate, profitLoss, memberSince } = $json;

let milestoneLabel = '';
let celebrationLevel = '';

switch (milestone) {
  case '10_trades':
  case '10':
    milestoneLabel = '10 trades';
    celebrationLevel = 'encouraging — they\'re just getting started';
    break;
  case '50_trades':
  case '50':
    milestoneLabel = '50 trades';
    celebrationLevel = 'impressive — they\'re becoming a regular';
    break;
  case '100_trades':
  case '100':
    milestoneLabel = '100 trades';
    celebrationLevel = 'amazing — they\'re a power user, make them feel elite';
    break;
  default:
    milestoneLabel = `${milestoneCount} trades`;
    celebrationLevel = 'notable achievement';
}

let statsBlock = '';
if (accuracy) statsBlock += `Personal accuracy: ${accuracy}%\n`;
if (winRate) statsBlock += `Win rate: ${winRate}%\n`;
if (profitLoss) statsBlock += `P&L: ${profitLoss}\n`;
if (memberSince) statsBlock += `Member since: ${memberSince}\n`;

const prompt = `Write a celebration Telegram DM for user "${username}" who just hit the ${milestoneLabel} milestone!

Milestone context:
- Achievement: ${milestoneLabel} completed
- Celebration level: ${celebrationLevel}
- Total predictions: ${totalPredictions}
${statsBlock ? `- Personal stats:\n${statsBlock}` : '- No personal stats available — keep it general'}

Message requirements:
- Start with genuine congratulations — make them feel special
- If personal stats are available, highlight their best metric
- For 10 trades: encourage them to keep going, mention features they might not know about
- For 50 trades: acknowledge their commitment, suggest /referral to share with friends (+7 days Premium for both)
- For 100 trades: make them feel like a VIP, strong referral CTA, hint at loyalty rewards
- Always end with a referral CTA: /referral gives both them and their friend +7 days Premium

Rules:
- Use HTML formatting (<b>, <i>, <code>) — NOT Markdown
- Keep under 700 characters
- Be genuinely celebratory, not corporate
- Never give financial advice
- Vary the celebration style — sometimes use a trophy theme, sometimes a journey metaphor, sometimes straight stats`;

return [{ json: { prompt, userId: $json.userId } }];

const response = $input.first().json;
let text = '';

if (response.content && response.content.length > 0) {
  text = response.content[0].text;
} else {
  text = '<b>Milestone Reached!</b>\n\nCongratulations on your trading journey with BTC Seer! Share the love with /referral — both you and your friend get +7 days Premium.';
}

return [{ json: { text, userId: $('Build Claude Prompt').first().json.userId } }];

const result = $input.first().json;
const userId = $('Extract Message Text').first().json.userId;
const success = result.ok === true;

console.log(`[Milestone] Sent to user ${userId}: ${success ? 'OK' : 'FAILED'}`);

return [{ json: { userId, success, timestamp: new Date().toISOString() } }];
